import{_ as i,c as a,o as n,ah as t}from"./chunks/framework.Cnj7lwEt.js";const k=JSON.parse('{"title":"GitHub-Nutzungsanleitung","description":"","frontmatter":{},"headers":[],"relativePath":"de/github-guide.md","filePath":"de/github-guide.md"}'),r={name:"de/github-guide.md"};function s(l,e,h,o,d,u){return n(),a("div",null,e[0]||(e[0]=[t(`<h1 id="github-nutzungsanleitung" tabindex="-1">GitHub-Nutzungsanleitung <a class="header-anchor" href="#github-nutzungsanleitung" aria-label="Permalink to “GitHub-Nutzungsanleitung”">​</a></h1><h2 id="_01-1-einfuhrung" tabindex="-1">01.1- Einführung <a class="header-anchor" href="#_01-1-einfuhrung" aria-label="Permalink to “01.1- Einführung”">​</a></h2><p>GitHub ist die weltweit größte Code-Hosting-Plattform, die Entwicklern leistungsstarke Versionskontrolle, kollaborative Entwicklung und Projektmanagement bietet.</p><h2 id="_01-2-grundkonzepte" tabindex="-1">01.2- Grundkonzepte <a class="header-anchor" href="#_01-2-grundkonzepte" aria-label="Permalink to “01.2- Grundkonzepte”">​</a></h2><h3 id="_01-21-repository" tabindex="-1">01.21- Repository <a class="header-anchor" href="#_01-21-repository" aria-label="Permalink to “01.21- Repository”">​</a></h3><p>Ein Repository ist der Speicherplatz eines Projekts, der alle Dateien, Ordner und die Änderungshistorie jeder Datei enthält.</p><h3 id="_01-22-branch" tabindex="-1">01.22- Branch <a class="header-anchor" href="#_01-22-branch" aria-label="Permalink to “01.22- Branch”">​</a></h3><p>Ein Branch ermöglicht die Entwicklung neuer Funktionen oder die Behebung von Fehlern, ohne den Hauptbranch zu beeinflussen.</p><h3 id="_01-23-commit" tabindex="-1">01.23- Commit <a class="header-anchor" href="#_01-23-commit" aria-label="Permalink to “01.23- Commit”">​</a></h3><p>Ein Commit ist ein Datensatz der Änderungen an einer Datei, jeder Commit erhält eine eindeutige ID.</p><h3 id="_01-24-pull-request" tabindex="-1">01.24- Pull Request <a class="header-anchor" href="#_01-24-pull-request" aria-label="Permalink to “01.24- Pull Request”">​</a></h3><p>Ein Pull Request ist eine Anfrage zum Zusammenführen von Änderungen in den Hauptbranch, die Code-Review und Diskussion erleichtert.</p><h2 id="_01-3-schnellstart" tabindex="-1">01.3- Schnellstart <a class="header-anchor" href="#_01-3-schnellstart" aria-label="Permalink to “01.3- Schnellstart”">​</a></h2><h3 id="_01-31-konto-erstellen" tabindex="-1">01.31- Konto erstellen <a class="header-anchor" href="#_01-31-konto-erstellen" aria-label="Permalink to “01.31- Konto erstellen”">​</a></h3><p>Besuchen Sie die <a href="https://github.com" target="_blank" rel="noreferrer">offizielle GitHub-Website</a> zur Registrierung.</p><h3 id="_01-32-repository-erstellen" tabindex="-1">01.32- Repository erstellen <a class="header-anchor" href="#_01-32-repository-erstellen" aria-label="Permalink to “01.32- Repository erstellen”">​</a></h3><ol><li>Klicken Sie auf die Schaltfläche &quot;+&quot; oben</li><li>Wählen Sie &quot;New repository&quot;</li><li>Geben Sie Repository-Namen und Beschreibung ein</li><li>Wählen Sie öffentlich oder privat</li><li>Klicken Sie auf &quot;Create repository&quot;</li></ol><h3 id="_01-33-repository-klonen" tabindex="-1">01.33- Repository klonen <a class="header-anchor" href="#_01-33-repository-klonen" aria-label="Permalink to “01.33- Repository klonen”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/username/repository.git</span></span></code></pre></div><h3 id="_01-34-branch-erstellen" tabindex="-1">01.34- Branch erstellen <a class="header-anchor" href="#_01-34-branch-erstellen" aria-label="Permalink to “01.34- Branch erstellen”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-35-anderungen-committen" tabindex="-1">01.35- Änderungen committen <a class="header-anchor" href="#_01-35-anderungen-committen" aria-label="Permalink to “01.35- Änderungen committen”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Neue Funktion hinzufügen&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-36-pull-request-erstellen" tabindex="-1">01.36- Pull Request erstellen <a class="header-anchor" href="#_01-36-pull-request-erstellen" aria-label="Permalink to “01.36- Pull Request erstellen”">​</a></h3><p>Erstellen Sie einen Pull Request auf der GitHub-Seite und warten Sie auf Review und Merge.</p><h2 id="_01-4-haufige-operationen" tabindex="-1">01.4- Häufige Operationen <a class="header-anchor" href="#_01-4-haufige-operationen" aria-label="Permalink to “01.4- Häufige Operationen”">​</a></h2><h3 id="_01-41-fork" tabindex="-1">01.41- Fork <a class="header-anchor" href="#_01-41-fork" aria-label="Permalink to “01.41- Fork”">​</a></h3><p>Verwenden Sie Fork, um das Projekt einer anderen Person in Ihr Konto zu kopieren und zu modifizieren.</p><h3 id="_01-42-stern" tabindex="-1">01.42- Stern <a class="header-anchor" href="#_01-42-stern" aria-label="Permalink to “01.42- Stern”">​</a></h3><p>Ein Stern zeigt an, dass Ihnen das Projekt gefällt, und Sie können es später leicht finden.</p><h3 id="_01-43-watch" tabindex="-1">01.43- Watch <a class="header-anchor" href="#_01-43-watch" aria-label="Permalink to “01.43- Watch”">​</a></h3><p>Verwenden Sie Watch, um Benachrichtigungen über Projektaktualisierungen zu erhalten.</p><h3 id="_01-44-issue" tabindex="-1">01.44- Issue <a class="header-anchor" href="#_01-44-issue" aria-label="Permalink to “01.44- Issue”">​</a></h3><p>Issues werden verwendet, um Fehler zu melden, Funktionen anzufordern oder Ideen zu diskutieren.</p><h2 id="_01-5-best-practices" tabindex="-1">01.5- Best Practices <a class="header-anchor" href="#_01-5-best-practices" aria-label="Permalink to “01.5- Best Practices”">​</a></h2><ol><li><strong>Klare Commit-Nachrichten</strong> - kommunizieren Sie anderen den Zweck jedes Commits</li><li><strong>Verwendung von Branches</strong> - entwickeln Sie nicht direkt auf dem Hauptbranch</li><li><strong>Regelmäßige Synchronisierung</strong> - synchronisieren Sie das lokale Repository mit dem Remote-Repository</li><li><strong>Code-Review</strong> - führen Sie Code-Reviews über Pull Requests durch</li><li><strong>Projektdokumentation</strong> - fügen Sie dem Projekt README und notwendige Dokumentation hinzu</li></ol><h2 id="_01-6-verwandte-ressourcen" tabindex="-1">01.6- Verwandte Ressourcen <a class="header-anchor" href="#_01-6-verwandte-ressourcen" aria-label="Permalink to “01.6- Verwandte Ressourcen”">​</a></h2><ul><li><a href="https://docs.github.com" target="_blank" rel="noreferrer">Offizielle GitHub-Dokumentation</a></li><li><a href="/de/91git.html">Git-Grundlagen-Tutorial</a></li><li><a href="/de/全部资源概述.html">Übersicht aller Ressourcen</a></li></ul>`,38)]))}const p=i(r,[["render",s]]);export{k as __pageData,p as default};
